      "/img/3D_prototype/lofarma_sin_almacen_stand_fabricado_por_standarte_en_madrid_005.avif",
      "/img/3D_prototype/lofarma_sin_almacen_stand_fabricado_por_standarte_en_madrid_006.avif"
